    op: Union[str, None] = None
    left: Union[ASTNode, None] = None
    right: Union[ASTNode, None] = None
    operand: Union[ASTNode, None] = None


class _Tokenizer:
    def __init__(self, expression: str):
        self.expression = expression
        self.pos = 0
        self.current_token: Tuple[str, Union[float, str, None]] = ("EOF", None)
        self._advance()

    def _skip_whitespace(self):
        while self.pos < len(self.expression) and self.expression[self.pos].isspace():
            self.pos += 1

    def _advance(self):
        self._skip_whitespace()
        if self.pos >= len(self.expression):
            self.current_token = ("EOF", None)
            return

        ch = self.expression[self.pos]

        if ch.isdigit() or ch == ".":
            start = self.pos
            has_dot = ch == "."
            self.pos += 1
            while self.pos < len(self.expression):
                c = self.expression[self.pos]
                if c.isdigit():
                    self.pos += 1
                elif c == "." and not has_dot:
                    has_dot = True
                    self.pos += 1
                else:
                    break
            num_str = self.expression[start : self.pos]
            try:
                self.current_token = ("NUMBER", float(num_str))
            except ValueError:
                raise ValueError(f"Invalid number: {num_str}")
            return

        if ch in "+-*/()":
            self.current_token = (ch, ch)
            self.pos += 1
            return

        raise ValueError(f"Invalid character: {ch}")

    def expect(self, token_type: str):
        if self.current_token[0] != token_type:
            raise ValueError(f"Expected {token_type}, got {self.current_token[0]}")
        value = self.current_token[1]
        self._advance()
        return value


def parse(expression: str) -> ASTNode:
    if not expression or not expression.strip():
        raise ValueError("Empty input")

    tokenizer = _Tokenizer(expression)
    node = _parse_expression(tokenizer)

    if tokenizer.current_token[0] != "EOF":
        raise ValueError(f"Unexpected token: {tokenizer.current_token[0]}")

    return node


def _parse_expression(tokenizer: _Tokenizer) -> ASTNode:
    node = _parse_term(tokenizer)

    while tokenizer.current_token[0] in ("+", "-"):
        op = tokenizer.current_token[0]
        tokenizer._advance()
        right = _parse_term(tokenizer)
        node = ASTNode(type="binop", op=op, left=node, right=right)

    return node


def _parse_term(tokenizer: _Tokenizer) -> ASTNode:
    node = _parse_factor(tokenizer)

    while tokenizer.current_token[0] in ("*", "/"):
        op = tokenizer.current_token[0]
        tokenizer._advance()
        right = _parse_factor(tokenizer)
        node = ASTNode(type="binop", op=op, left=node, right=right)

    return node


def _parse_factor(tokenizer: _Tokenizer) -> ASTNode:
    if tokenizer.current_token[0] == "-":
        tokenizer._advance()
        operand = _parse_factor(tokenizer)
        return ASTNode(type="unary", op="-", operand=operand)

    if tokenizer.current_token[0] == "+":
        tokenizer._advance()
        return _parse_factor(tokenizer)

    if tokenizer.current_token[0] == "(":
        tokenizer._advance()
        node = _parse_expression(tokenizer)
        tokenizer.expect(")")
        return node

    if tokenizer.current_token[0] == "NUMBER":
        value = tokenizer.current_token[1]
        tokenizer._advance()
        return ASTNode(type="number", value=value if isinstance(value, float) else 0.0)

    raise ValueError(f"Unexpected token: {tokenizer.current_token[0]}")


def evaluate(node: ASTNode) -> float:
    if node.type == "number":
        if node.value is None:
            raise ValueError("Number node has no value")
        return node.value

    if node.type == "unary":
        if node.operand is None:
            raise ValueError("Unary node has no operand")
        if node.op == "-":
            return -evaluate(node.operand)
        raise ValueError(f"Unknown unary operator: {node.op}")

    if node.type == "binop":
        if node.left is None or node.right is None:
            raise ValueError("Binary operator node missing operands")
        if node.op is None:
            raise ValueError("Binary operator node has no operator")

        left_val = evaluate(node.left)
        right_val = evaluate(node.right)

        if node.op == "+":
            return left_val + right_val
        if node.op == "-":
            return left_val - right_val
        if node.op == "*":
            return left_val * right_val
        if node.op == "/":
            if right_val == 0:
                raise ZeroDivisionError("Division by zero")
            return left_val / right_val

        raise ValueError(f"Unknown operator: {node.op}")

    raise ValueError(f"Unknown node type: {node.type}")
